/// <summary>
/// Process that creates a Transfer Journal (<c>InventJournalTable</c>)
/// and its lines (<c>InventJournalTrans</c>) from an Operation (<c>ETGSPAINPurchOperationTable</c>) (Controller) for the ETGSPAIN model.
/// </summary>
class ETGSPAINPurchCreateInventJournalTableController extends SysOperationServiceController
{
    ClassDescription classDescription;

}

Method.Source:
/// <summary>
/// Overwritten method <c>defaultCaption</c> to customize the dialog title.
/// </summary>
/// <returns>Returns the <c>ClassDescription</c> of the class.</returns>
public ClassDescription defaultCaption()
{
    return this.parmClassDescription();
}

/// <summary>
/// Method <c>parmClassDescription</c> for the <c>ClassDescription</c> of the class.
/// </summary>
/// <param name = "_classDescription"><c>ClassDescription</c></param>
/// <returns>Returns the <c>ClassDescription</c>.</returns>
public ClassDescription parmClassDescription(ClassDescription _classDescription = classDescription)
{
    classDescription = _classDescription;
    return classDescription;
}

/// <summary>
/// Method <c>construct</c>, creates an instance of the class.
/// </summary>
/// <param name = "_args">Args</param>
/// <param name = "_executionMode">SysOperationExecutionMode</param>
/// <returns>Returns an instance of <c>ETGSPAINPurchCreateInventJournalTableController</c>.</returns>
/// <remarks>By default, if not provided, the execution mode is <c>Synchronous</c>.</remarks>
public static ETGSPAINPurchCreateInventJournalTableController construct(Args _args,
    SysOperationExecutionMode	_executionMode = SysOperationExecutionMode::Synchronous)
{
    ETGSPAINPurchCreateInventJournalTableController	controller;        

    controller = new ETGSPAINPurchCreateInventJournalTableController();
    controller.parmExecutionMode(_executionMode);
    controller.parmArgs(_args);

    controller.parmClassName(classStr(ETGSPAINPurchCreateInventJournalTableService));

    controller.parmMethodName(methodStr(ETGSPAINPurchCreateInventJournalTableService, "createInventJournals"));
    controller.parmClassDescription("@ETGSPAINLabels:CreateTransactionsButtonGroup");

    MultiSelectionHelper	multiSelectionHelper;
    Set						recordSet;
    ETGSPAINPurchOperationTable	ETGSPAINPurchOperationTable;        

    if (_args && _args.caller() is FormRun)
    {
        recordSet				= new Set(Types::Record);
        multiselectionHelper	= MultiSelectionHelper::createFromCaller(_args.caller());

        ETGSPAINPurchOperationTable	= multiselectionHelper.getFirst();

        recordSet.add(ETGSPAINPurchOperationTable);

    }

    ETGSPAINPurchCreateInventJournalTableContract dataContract = controller.getDataContractObject();

    dataContract.parmRecordCon(recordSet.pack());

    return controller;
}

/// <summary>
/// Method <c>main</c>, invoked from the MenuItem to execute the service.
/// </summary>
/// <param name = "_args">Args</param>
public static void main(Args _args)
{
    ETGSPAINPurchCreateInventJournalTableController controller;
    SysOperationStartResult sysOperationStartResult;
    controller = ETGSPAINPurchCreateInventJournalTableController::construct(_args, SysOperationExecutionMode::Synchronous);
    controller.parmArgs(_args);
    controller.parmShowDialog(false);

    sysOperationStartResult = controller.startOperation();
}
